import { Suspense, lazy } from 'react'
import { Routes, Route, useLocation } from 'react-router'
import MainLayout from './layouts/MainLayout'
import ErrorBoundary from './components/ErrorBoundary'

// Lazy load pages for code splitting
const Home = lazy(() => import('./pages/Home'))
const About = lazy(() => import('./pages/About'))
const ServicesPage = lazy(() => import('./pages/ServicesPage'))
const ProjectsPage = lazy(() => import('./pages/ProjectsPage'))
const ProjectDetail = lazy(() => import('./pages/ProjectDetail'))
const TeamPage = lazy(() => import('./pages/TeamPage'))
const ContactPage = lazy(() => import('./pages/ContactPage'))
const Blog = lazy(() => import('./pages/Blog'))
const BlogPost = lazy(() => import('./pages/BlogPost'))
const NotFound = lazy(() => import('./pages/NotFound'))

function PageLoader() {
  return (
    <div className="min-h-[60vh] flex items-center justify-center">
      <div className="flex flex-col items-center gap-3">
        <div className="w-8 h-8 border-2 border-accent-lime/20 border-t-accent-lime rounded-full animate-spin" />
        <span className="font-mono text-xs text-text-muted animate-pulse">Loading…</span>
      </div>
    </div>
  )
}

export default function App() {
  const location = useLocation()

  // Update document title based on route
  const titles: Record<string, string> = {
    '/': 'Universe Software — Digital Solutions for Cambodia',
    '/about': 'About — Universe Software',
    '/services': 'Services — Universe Software',
    '/work': 'Our Work — Universe Software',
    '/team': 'Team — Universe Software',
    '/contact': 'Contact — Universe Software',
    '/blog': 'Blog — Universe Software',
  }

  const baseTitle = titles[location.pathname] ?? 'Universe Software'
  if (document.title !== baseTitle) {
    document.title = baseTitle
  }

  return (
    <ErrorBoundary>
      <MainLayout>
        <Suspense fallback={<PageLoader />}>
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/about" element={<About />} />
            <Route path="/services" element={<ServicesPage />} />
            <Route path="/work" element={<ProjectsPage />} />
            <Route path="/work/:id" element={<ProjectDetail />} />
            <Route path="/team" element={<TeamPage />} />
            <Route path="/contact" element={<ContactPage />} />
            <Route path="/blog" element={<Blog />} />
            <Route path="/blog/:slug" element={<BlogPost />} />
            <Route path="*" element={<NotFound />} />
          </Routes>
        </Suspense>
      </MainLayout>
    </ErrorBoundary>
  )
}

import { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MessageCircle, X, Send } from 'lucide-react';
import OpenAI from 'openai';

interface Message {
  id: string;
  text: string;
  sender: 'user' | 'bot';
}

const spring = { type: 'spring' as const, stiffness: 300, damping: 25 };

const openai = new OpenAI({
  apiKey: import.meta.env.VITE_NVIDIA_API_KEY || 'missing-api-key',
  baseURL: `${window.location.origin}/api/nvidia`,
  dangerouslyAllowBrowser: true,
});
const systemPrompt = 'You are a helpful assistant for Universe Software, a product engineering company. Be concise and helpful.';



export default function ChatWidget() {
  const [open, setOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'chat' | 'email'>('chat');
  const [isLoading, setIsLoading] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      text: "Hi! Welcome to Universe Software. How can we help you today?",
      sender: 'bot',
    },
  ]);
  const [input, setInput] = useState('');
  const [formData, setFormData] = useState({ name: '', email: '', company: '', message: '' });
  const [formSubmitted, setFormSubmitted] = useState(false);
  const [stopPulse, setStopPulse] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(() => setStopPulse(true), 5000);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg: Message = { id: Date.now().toString(), text: input, sender: 'user' };
    setMessages((prev) => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);
    // Add typing placeholder
    const typingMsg: Message = { id: 'typing', text: 'typing...', sender: 'bot' };
    setMessages((prev) => [...prev, typingMsg]);
    try {
      const stream = await openai.chat.completions.create({
        model: import.meta.env.VITE_MODEL_LLM_SELECTION || 'nvidia/openai/gpt-oss-120b',
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: input },
        ],
        temperature: 1,
        top_p: 1,
        max_tokens: 512,
        stream: true,
      });
      let full = '';
      for await (const part of stream as any) {
        const delta = part?.choices?.[0]?.delta?.content;
        if (delta) {
          full += delta;
          setMessages((prev) =>
            prev.map((m) => (m.id === 'typing' ? { ...m, text: full } : m))
          );
        }
      }
      // Replace typing with final message
      setMessages((prev) =>
        prev.filter((m) => m.id !== 'typing').concat({ id: Date.now().toString(), text: full, sender: 'bot' })
      );
    } catch (error: any) {
      console.error(error);
      const errorMessage = error?.message || 'Connection lost to the neural network.';
      setMessages((prev) =>
        prev.filter((m) => m.id !== 'typing').concat({ 
          id: Date.now().toString(), 
          text: `Error [${error?.status || 403}]: ${errorMessage}. Please check your API configuration or model access.`, 
          sender: 'bot' 
        })
      );
    } finally {
      setIsLoading(false);
    }
  };

  const handleFormSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.email || !formData.message) return;
    setFormSubmitted(true);
  };

  return (
    <>
      {/* FAB */}
      <motion.button
        onClick={() => setOpen(!open)}
        className="fixed bottom-6 right-6 z-50 w-14 h-14 flex items-center justify-center liquid-glass-btn !rounded-full shadow-2xl"
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
        aria-label="Open chat"
      >
        {!stopPulse && (
          <span className="absolute inset-0 rounded-full bg-white/20 animate-pulse-ring" />
        )}
        {open ? (
          <X size={24} className="text-text-primary relative z-10" />
        ) : (
          <MessageCircle size={24} className="text-text-primary relative z-10" />
        )}
      </motion.button>

      {/* Modal */}
      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ opacity: 0, scale: 0.9, y: 10 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.9, y: 10 }}
            transition={spring}
            className="fixed bottom-24 right-6 z-50 w-[calc(100vw-48px)] max-w-[420px] max-h-[600px] liquid-glass !rounded-[2.5rem] shadow-[0_32px_128px_-16px_rgba(0,0,0,0.6)] flex flex-col overflow-hidden"
            role="dialog"
            aria-label="Chat widget"
          >
            {/* Header / Tab bar */}
            <div className="flex bg-white/5 backdrop-blur-md border-b border-white/10 px-2 py-2">
              <button
                onClick={() => setActiveTab('chat')}
                className={`flex-1 py-2.5 rounded-[1.5rem] font-mono text-[10px] uppercase tracking-[0.1em] transition-all relative ${
                  activeTab === 'chat' ? 'bg-white/10 text-text-primary shadow-sm' : 'text-text-muted hover:text-text-secondary'
                }`}
              >
                Intelligent Chat
              </button>
              <button
                onClick={() => setActiveTab('email')}
                className={`flex-1 py-2.5 rounded-[1.5rem] font-mono text-[10px] uppercase tracking-[0.1em] transition-all relative ${
                  activeTab === 'email' ? 'bg-white/10 text-text-primary shadow-sm' : 'text-text-muted hover:text-text-secondary'
                }`}
              >
                Direct Inquiry
              </button>
            </div>

            {/* Content */}
            <div className="flex-1 overflow-hidden bg-gradient-to-b from-transparent to-black/10">
              <AnimatePresence mode="wait">
                {activeTab === 'chat' ? (
                  <motion.div
                    key="chat"
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="flex flex-col h-full"
                  >
                    {/* Messages */}
                    <div className="flex-1 overflow-y-auto p-6 space-y-4 min-h-0 scrollbar-hide">
                      {messages.map((msg) => (
                        <div
                          key={msg.id}
                          className={`flex ${
                            msg.sender === 'user' ? 'justify-end' : 'justify-start'
                          }`}
                        >
                          <div
                            className={`max-w-[85%] px-5 py-3 rounded-[1.5rem] text-sm leading-relaxed ${
                              msg.sender === 'user'
                                ? 'bg-white/15 text-text-primary rounded-tr-sm border border-white/10 shadow-sm'
                                : 'bg-black/20 backdrop-blur-md text-text-secondary rounded-tl-sm border border-white/5'
                            }`}
                          >
                            {msg.text}
                          </div>
                        </div>
                      ))}
                      <div ref={messagesEndRef} />
                    </div>

                    {/* Input */}
                    <div className="p-4 bg-white/5 backdrop-blur-xl border-t border-white/10 flex gap-3">
                      <input
                        type="text"
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                        placeholder={isLoading ? 'Computing...' : 'Ask anything...'}
                        disabled={isLoading}
                        className="flex-1 bg-black/20 border border-white/10 rounded-[1.2rem] px-5 py-3 font-mono text-xs text-text-primary placeholder:text-text-muted focus:outline-none focus:border-white/30 disabled:opacity-50 transition-all shadow-inner"
                      />
                      <button
                        onClick={handleSend}
                        disabled={isLoading}
                        className="w-11 h-11 flex items-center justify-center bg-white/10 rounded-full text-text-primary hover:bg-white/20 transition-all disabled:opacity-50 border border-white/10 shadow-sm"
                        aria-label="Send message"
                      >
                        <Send size={16} />
                      </button>
                    </div>
                  </motion.div>
                ) : (
                  <motion.div
                    key="email"
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="p-6 overflow-y-auto scrollbar-hide"
                  >
                    {formSubmitted ? (
                      <div className="text-center py-12">
                        <div className="w-16 h-16 bg-white/10 rounded-full flex items-center justify-center mx-auto mb-6 border border-white/10 shadow-lg">
                          <motion.div
                            initial={{ scale: 0 }}
                            animate={{ scale: 1 }}
                            className="text-accent-lime"
                          >
                            ✓
                          </motion.div>
                        </div>
                        <p className="text-xl text-text-primary font-medium tracking-tight">
                          Transmission Received
                        </p>
                        <p className="text-base text-text-muted mt-3 leading-relaxed">
                          Our team will reach out to you within 24 hours.
                        </p>
                      </div>
                    ) : (
                      <form onSubmit={handleFormSubmit} className="space-y-4">
                        <div className="space-y-3">
                          <input
                            type="text"
                            placeholder="Full Name"
                            required
                            value={formData.name}
                            onChange={(e) =>
                              setFormData({ ...formData, name: e.target.value })
                            }
                            className="w-full bg-black/20 border border-white/10 rounded-[1rem] px-5 py-3.5 font-mono text-xs text-text-primary placeholder:text-text-muted focus:outline-none focus:border-white/30 transition-all"
                          />
                          <input
                            type="email"
                            placeholder="Email Address"
                            required
                            value={formData.email}
                            onChange={(e) =>
                              setFormData({ ...formData, email: e.target.value })
                            }
                            className="w-full bg-black/20 border border-white/10 rounded-[1rem] px-5 py-3.5 font-mono text-xs text-text-primary placeholder:text-text-muted focus:outline-none focus:border-white/30 transition-all"
                          />
                          <input
                            type="text"
                            placeholder="Organization (Optional)"
                            value={formData.company}
                            onChange={(e) =>
                              setFormData({ ...formData, company: e.target.value })
                            }
                            className="w-full bg-black/20 border border-white/10 rounded-[1rem] px-5 py-3.5 font-mono text-xs text-text-primary placeholder:text-text-muted focus:outline-none focus:border-white/30 transition-all"
                          />
                          <textarea
                            placeholder="How can we help?"
                            required
                            rows={4}
                            value={formData.message}
                            onChange={(e) =>
                              setFormData({ ...formData, message: e.target.value })
                            }
                            className="w-full bg-black/20 border border-white/10 rounded-[1.2rem] px-5 py-4 font-mono text-xs text-text-primary placeholder:text-text-muted focus:outline-none focus:border-white/30 transition-all resize-none"
                          />
                        </div>
                        <button
                          type="submit"
                          className="w-full py-4 mt-2 rounded-[1.2rem] bg-white text-black text-xs font-semibold uppercase tracking-widest hover:bg-white/90 active:scale-[0.98] transition-all shadow-xl"
                        >
                          Send Transmission
                        </button>
                      </form>
                    )}
                  </motion.div>
                )}
              </AnimatePresence>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}

import React from "react";
import { motion, useScroll, useSpring } from "framer-motion";

/**
 * Fixed HUD component providing a scroll progress bar and static information.
 * - Full‑screen fixed container with pointer-events disabled.
 * - Top progress bar reflects the page scroll using a spring‑animated value.
 * - Bottom corners display placeholder coordinates and speed.
 */
const HUD: React.FC = () => {
  // framer‑motion hook to get scroll progress (0 → 1)
  const { scrollYProgress } = useScroll();
  // Smooth the progress value with a spring for a nicer animation
  const spring = useSpring(scrollYProgress, { stiffness: 100, damping: 30 });

  return (
    <div className="fixed inset-0 pointer-events-none z-50 flex flex-col justify-between">
      {/* Scroll progress bar at the top */}
      <motion.div
        className="h-1 bg-accent-lime origin-left"
        style={{ scaleX: spring }}
      />

      {/* Bottom info bar */}
      <div className="flex justify-between px-4 pb-2 text-text-primary font-mono text-xs">
        <span>Coordinates: UNKNOWN</span>
        <span>Speed: Warp 1</span>
      </div>
    </div>
  );
};

export default HUD;

import { useEffect, useState } from 'react';
import { motion, useSpring } from 'framer-motion';

export default function ProbeCursor() {
  const [isVisible, setIsVisible] = useState(false);

  // Main targeting dot
  const springConfig = { stiffness: 300, damping: 20, mass: 0.5 };
  const cursorX = useSpring(0, springConfig);
  const cursorY = useSpring(0, springConfig);

  // Trailing particles setup
  const numParticles = 5;
  const particles = Array.from({ length: numParticles }).map((_, i) => ({
    x: useSpring(0, { stiffness: 200 - i * 20, damping: 20 + i * 5, mass: 0.5 + i * 0.1 }),
    y: useSpring(0, { stiffness: 200 - i * 20, damping: 20 + i * 5, mass: 0.5 + i * 0.1 }),
  }));

  useEffect(() => {
    const isTouchDevice = 'ontouchstart' in window || navigator.maxTouchPoints > 0;
    if (isTouchDevice || window.innerWidth < 1024) return;

    const handleMouseMove = (e: MouseEvent) => {
      cursorX.set(e.clientX);
      cursorY.set(e.clientY);

      particles.forEach((p) => {
        p.x.set(e.clientX);
        p.y.set(e.clientY);
      });

      if (!isVisible) setIsVisible(true);
    };

    const handleMouseEnter = () => setIsVisible(true);
    const handleMouseLeave = () => setIsVisible(false);

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseenter', handleMouseEnter);
    document.addEventListener('mouseleave', handleMouseLeave);

    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseenter', handleMouseEnter);
      document.removeEventListener('mouseleave', handleMouseLeave);
    };
  }, [cursorX, cursorY, particles, isVisible]);

  const isTouchDevice = typeof window !== 'undefined' && ('ontouchstart' in window || navigator.maxTouchPoints > 0);
  if (isTouchDevice || (typeof window !== 'undefined' && window.innerWidth < 1024)) return null;

  return (
    <>
      {/* Trailing particles */}
      {particles.map((p, i) => (
        <motion.div
          key={`particle-${i}`}
          className="fixed top-0 left-0 pointer-events-none z-[9998] mix-blend-screen"
          style={{
            x: p.x,
            y: p.y,
            translateX: '-50%',
            translateY: '-50%',
          }}
        >
          <motion.div
            className="w-1 h-1 rounded-full bg-accent-lime/50"
            animate={{ opacity: isVisible ? 1 - i * 0.15 : 0 }}
            transition={{ duration: 0.15 }}
          />
        </motion.div>
      ))}

      {/* Main targeting dot */}
      <motion.div
        className="fixed top-0 left-0 pointer-events-none z-[9999] mix-blend-screen"
        style={{
          x: cursorX,
          y: cursorY,
          translateX: '-50%',
          translateY: '-50%',
        }}
      >
        <motion.div
          className="w-2 h-2 rounded-full bg-white shadow-[0_0_10px_white]"
          animate={{ opacity: isVisible ? 1 : 0 }}
          transition={{ duration: 0.15 }}
        />
      </motion.div>
    </>
  );
}

