// src/components/UniverseCanvas.tsx
import React, { Suspense, useMemo } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';
import { Stars, Float, useTexture } from '@react-three/drei';



// ---------------------------------------------------------------------------
// RealUniversePlanet — textured Earth with clouds
// ---------------------------------------------------------------------------
const RealUniversePlanet: React.FC<{
  position: [number, number, number];
  scale: number;
}> = ({ position, scale }) => {
  const [colorMap, normalMap, specularMap, cloudMap] = useTexture([
    '/textures/planet_color.jpg',
    '/textures/planet_normal.jpg',
    '/textures/planet_specular.jpg',
    '/textures/planet_clouds.png',
  ]);

  return (
    <group position={position}>
      {/* Planet surface */}
      <mesh>
        <sphereGeometry args={[scale, 64, 64]} />
        <meshStandardMaterial
          map={colorMap}
          normalMap={normalMap}
          normalScale={new THREE.Vector2(2, 2)}
          roughnessMap={specularMap}
          roughness={0.8}
          metalness={0.4}
        />
      </mesh>
      {/* Clouds layer */}
      <mesh scale={scale * 1.015}>
        <sphereGeometry args={[scale, 64, 64]} />
        <meshStandardMaterial
          map={cloudMap}
          transparent
          opacity={0.6}
          depthWrite={false}
          side={THREE.DoubleSide}
        />
      </mesh>
    </group>
  );
};

// ---------------------------------------------------------------------------
// ParallaxScene — scroll-driven camera + stars + earth + orbiters
// ---------------------------------------------------------------------------
const ParallaxScene: React.FC = () => {
  const { camera } = useThree();

  useFrame(() => {
    const scrollY = window.scrollY;
    const docHeight = document.body.scrollHeight - window.innerHeight;
    const scrollProgress = docHeight > 0 ? scrollY / docHeight : 0;

    // Camera orbits around the earth while slowly descending / zooming
    const angle = scrollProgress * Math.PI * 0.8; // ~144° arc
    const radius = 18 - scrollProgress * 6; // 18 → 12

    camera.position.x = Math.sin(angle) * radius;
    camera.position.z = Math.cos(angle) * radius;
    camera.position.y = Math.sin(scrollProgress * Math.PI * 0.5) * 3;
    camera.lookAt(0, 0, 0);
  });

  return (
    <>
      {/* Layer 0: Star field */}
      <Stars
        radius={100}
        depth={50}
        count={5000}
        factor={4}
        saturation={0}
        fade
        speed={1}
      />

      {/* Layer 1: Earth — single planet at centre */}
      <Float speed={2} rotationIntensity={0.5}>
        <RealUniversePlanet position={[0, 0, 0]} scale={3} />
      </Float>

    </>
  );
};

// ---------------------------------------------------------------------------
// Main export
// ---------------------------------------------------------------------------
export default function UniverseCanvas() {
  return (
    <div className="fixed inset-0 z-0 bg-[#0a0a0f]">
      <Canvas>
        <Suspense fallback={null}>
          {/* Lighting */}
          <ambientLight intensity={0.4} />
          <directionalLight position={[10, 10, 5]} intensity={1.2} />
          <pointLight position={[-8, 4, -5]} intensity={0.5} color="#6688ff" />

          {/* Scene */}
          <ParallaxScene />
        </Suspense>
      </Canvas>
    </div>
  );
}

import { useEffect, useState } from 'react'
import { motion, useInView } from 'framer-motion'
import { useRef } from 'react'
import { Calendar, MapPin, Target, Eye, Rocket, Award } from 'lucide-react'
import { dataService } from '../services/dataService'
import type { AboutUsData, VisionData, JourneyData } from '../services/dataService'

const ease: [number, number, number, number] = [0.16, 1, 0.3, 1]

function InfoCard({ icon: Icon, title, children, delay = 0 }: any) {
  const ref = useRef(null)
  const isInView = useInView(ref, { once: true, margin: '-80px' })
  return (
    <motion.div
      ref={ref}
      initial={{ opacity: 0, y: 24 }}
      animate={isInView ? { opacity: 1, y: 0 } : {}}
      transition={{ duration: 0.6, delay, ease }}
      className="liquid-glass-card p-8 rounded-2xl"
    >
      <div className="inline-flex items-center justify-center w-10 h-10 rounded-full bg-accent-lime/10 text-accent-lime mb-4">
        <Icon size={20} />
      </div>
      <h3 className="font-display text-xl text-text-primary mb-2">{title}</h3>
      <div className="text-text-muted text-base leading-relaxed">{children}</div>
    </motion.div>
  )
}

export default function About() {
  const [about, setAbout] = useState<AboutUsData | null>(null)
  const [visions, setVisions] = useState<VisionData | null>(null)
  const [missions, setMissions] = useState<VisionData | null>(null)
  const [goals, setGoals] = useState<VisionData | null>(null)
  const [journey, setJourney] = useState<JourneyData | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    Promise.all([
      dataService.getAboutUs(),
      dataService.getVisions(),
      dataService.getMissions(),
      dataService.getGoals(),
      dataService.getJourney(),
    ])
      .then(([a, v, m, g, j]) => {
        setAbout(a)
        setVisions(v)
        setMissions(m)
        setGoals(g)
        setJourney(j)
      })
      .catch(console.error)
      .finally(() => setLoading(false))
  }, [])

  const heroRef = useRef(null)
  const isHeroInView = useInView(heroRef, { once: true })

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="font-mono text-xs text-text-muted animate-pulse">Loading…</div>
      </div>
    )
  }

  return (
    <div className="pt-24 pb-20">
      {/* Hero */}
      <section className="max-w-[1280px] mx-auto px-4 sm:px-6 py-16 md:py-24" ref={heroRef}>
        <motion.p
          initial={{ opacity: 0, y: 20 }}
          animate={isHeroInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6, ease }}
          className="font-mono text-xs tracking-[0.08em] uppercase text-accent-lime mb-4"
        >
          {about?.sectionLabel}
        </motion.p>
        <motion.h1
          initial={{ opacity: 0, y: 24 }}
          animate={isHeroInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6, delay: 0.1, ease }}
          className="font-display text-[clamp(2.5rem,6vw,5rem)] leading-[1.05] text-text-primary max-w-4xl"
        >
          {about?.headline}
        </motion.h1>
        <motion.p
          initial={{ opacity: 0, y: 24 }}
          animate={isHeroInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6, delay: 0.2, ease }}
          className="text-lg text-text-secondary mt-6 max-w-2xl leading-relaxed"
        >
          {about?.description}
        </motion.p>

        <motion.div
          initial={{ opacity: 0, y: 24 }}
          animate={isHeroInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6, delay: 0.3, ease }}
          className="flex flex-wrap gap-6 mt-10"
        >
          <div className="flex items-center gap-2 text-text-muted">
            <Calendar size={16} className="text-accent-lime" />
            <span className="font-mono text-xs">Founded {about?.foundedYear}</span>
          </div>
          <div className="flex items-center gap-2 text-text-muted">
            <MapPin size={16} className="text-accent-lime" />
            <span className="font-mono text-xs">
