              <p key={i} className="mb-2">
                {b}
              </p>
            ))}
          </InfoCard>
          <InfoCard icon={Rocket} title={goals?.title || "Goals"} delay={0.2}>
            {goals?.bullets?.map((b, i) => (
              <p key={i} className="mb-2">
                {b}
              </p>
            ))}
