import { useRef, useState, useEffect } from 'react';
import { motion, useInView } from 'framer-motion';
import { Copy, Check, Mail, Phone } from 'lucide-react';

const ease: [number, number, number, number] = [0.16, 1, 0.3, 1];

export default function Contact() {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: '-100px' });
  const [copied, setCopied] = useState(false);
  const [contactData, setContactData] = useState<any>(null);

  useEffect(() => {
    fetch('/data/company_contact.json')
      .then((res) => res.json())
      .then(setContactData)
      .catch((err) => console.error('Failed to load contact data', err));
  }, []);


  const handleCopy = () => {
    const email = contactData?.contacts?.find((c: any) => c.type === 'email')?.value ?? '';
    if (email) {
      navigator.clipboard.writeText(email);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const handleScroll = (e: React.MouseEvent<HTMLAnchorElement>, href: string) => {
    e.preventDefault();
    const el = document.querySelector(href);
    if (el) el.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <section
      id="contact"
      className="w-full py-[200px] bg-transparent relative overflow-hidden"
      ref={ref}
      style={{
        clipPath: 'polygon(0 80px, 100% 0, 100% 100%, 0 100%)',
        marginTop: '-80px',
        paddingTop: '280px',
      }}
    >
      {/* Accent glow */}
      <div
        className="absolute inset-0 pointer-events-none"
        style={{
          background:
            'radial-gradient(ellipse 60% 40% at 50% 0%, rgba(200,241,53,0.06) 0%, transparent 70%)',
        }}
      />

      <div className="relative max-w-[800px] mx-auto px-6 text-center">
          {/* Section label */}
          <motion.p
            initial={{ opacity: 0, y: 20 }}
            animate={isInView ? { opacity: 1, y: 0 } : {}}
            transition={{ duration: 0.6, ease }}
            className="font-mono text-xs tracking-[0.08em] uppercase text-accent-lime"
          >
            {contactData?.sectionLabel}
          </motion.p>

          {/* Title */}
          <motion.h2
            initial={{ opacity: 0, y: 20 }}
            animate={isInView ? { opacity: 1, y: 0 } : {}}
            transition={{ delay: 0.1, duration: 0.6, ease }}
            className="font-display text-[clamp(2.5rem,5vw,5rem)] leading-[1.05] text-text-primary mt-4"
          >
            {contactData?.title}
          </motion.h2>

          {/* Subtitle */}
          {contactData?.subtitle && (
            <motion.p
              initial={{ opacity: 0, y: 20 }}
              animate={isInView ? { opacity: 1, y: 0 } : {}}
              transition={{ delay: 0.15, duration: 0.6, ease }}
              className="font-mono text-sm text-text-muted mt-2"
            >
              {contactData?.subtitle}
            </motion.p>
          )}

          {/* Action buttons */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={isInView ? { opacity: 1, y: 0 } : {}}
            transition={{ delay: 0.3, duration: 0.6, ease }}
            className="flex flex-wrap justify-center gap-5 mt-12"
          >
            <a
              href="#"
              onClick={(e) => handleScroll(e, '#contact')}
              className="inline-flex items-center px-8 py-3.5 rounded-full liquid-glass-btn text-text-primary text-base font-medium transition-all"
            >
              Start a Project
            </a>
            <a
              href="#"
              onClick={(e) => handleScroll(e, '#contact')}
              className="inline-flex items-center px-8 py-3.5 rounded-full liquid-glass-btn text-text-primary text-base font-medium transition-all"
            >
              Book a Call →
            </a>
          </motion.div>

          {/* Contacts list */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={isInView ? { opacity: 1 } : {}}
            transition={{ delay: 0.5, duration: 0.6, ease }}
            className="mt-8 flex flex-col items-center gap-4"
          >
            {contactData?.contacts?.map((c: any) => (
              <a
                key={c.type}
                href={c.href}
                className="font-mono text-sm text-text-secondary hover:text-accent-lime transition-colors inline-flex items-center gap-2 group"
                onClick={c.type === 'email' ? (e) => { e.preventDefault(); handleCopy(); } : undefined}
              >
                {c.type === 'email' ? <Mail size={14} /> : <Phone size={14} />}
                {c.value}
                {c.type === 'email' && (
                  <button
                    className="opacity-0 group-hover:opacity-100 transition-opacity"
                    aria-label="Copy email"
                  >
                    {copied ? <Check size={14} className="text-accent-lime" /> : <Copy size={14} />}
                  </button>
                )}
              </a>
            ))}
          </motion.div>

          {/* Tagline */}
          {contactData?.tagline && (
            <motion.p
              initial={{ opacity: 0 }}
              animate={isInView ? { opacity: 1 } : {}}
              transition={{ delay: 0.6, duration: 0.6, ease }}
              className="font-mono text-sm text-text-muted mt-4"
            >
              {contactData?.tagline}
            </motion.p>
          )}
      </div>
    </section>
  );
}

// Our Journey Timeline Section
import { useEffect, useState, useRef } from 'react';
import { motion, useInView } from 'framer-motion';

const PLANET_IMAGES = [
  '/images/planet-aether.png',
  '/images/planet-forge.png',
  '/images/planet-neural.png',
  '/images/planet-nexus.png',
  '/images/planet-oracle.png',
];

type Milestone = {
  year: string;
  title: string;
  description: string;
};

type JourneyData = {
  sectionLabel: string;
  title: string;
  subtitle?: string;
  milestones: Milestone[];
};

const ease: [number, number, number, number] = [0.16, 1, 0.3, 1];

export default function OurJourney() {
  const [data, setData] = useState<JourneyData | null>(null);
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: '-100px' });

  useEffect(() => {
    const fetchData = async () => {
      const res = await fetch('/data/our_journey.json');
      const json = await res.json();
      setData(json);
    };
    fetchData();
  }, []);

  if (!data) return null;

  return (
    <section id="journey" className="w-full py-20 md:py-[140px] bg-transparent" ref={ref}>
      <div className="max-w-[1280px] mx-auto px-4 sm:px-6">

        {/* Section Header */}
        <div className="text-center mb-12 md:mb-16">
          <motion.p
            initial={{ opacity: 0, y: 20 }}
            animate={isInView ? { opacity: 1, y: 0 } : {}}
            transition={{ duration: 0.6, ease }}
            className="font-mono text-xs tracking-[0.08em] uppercase text-accent-lime"
          >
            {data.sectionLabel}
          </motion.p>
          <motion.h2
            initial={{ opacity: 0, y: 20 }}
            animate={isInView ? { opacity: 1, y: 0 } : {}}
            transition={{ delay: 0.1, duration: 0.6, ease }}
            className="font-display text-[clamp(2rem,6vw,5rem)] leading-[1.05] text-text-primary mt-4"
          >
            {data.title}
          </motion.h2>
          {data.subtitle && (
            <motion.p
              initial={{ opacity: 0, y: 20 }}
              animate={isInView ? { opacity: 1, y: 0 } : {}}
              transition={{ delay: 0.2, duration: 0.6, ease }}
              className="text-lg md:text-xl text-text-secondary mt-4 max-w-[560px] mx-auto"
            >
              {data.subtitle}
            </motion.p>
          )}
        </div>

        {/* ── Mobile timeline (single column, line on left) ── */}
        <div className="block md:hidden relative">
          {/* Left-side vertical line */}
          <div className="absolute left-6 top-0 w-px h-full bg-border-surface pointer-events-none" />
          <div className="space-y-10 pl-16">
            {data.milestones.map((m, idx) => (
              <MobileCard key={m.year} milestone={m} index={idx} planet={PLANET_IMAGES[idx % PLANET_IMAGES.length]} />
            ))}
          </div>
        </div>

        {/* ── Desktop timeline (alternating left/right) ── */}
        <div className="hidden md:block relative">
          <div className="absolute left-1/2 top-0 w-px h-full bg-border-surface pointer-events-none" />
          <div className="space-y-32">
            {data.milestones.map((m, idx) => (
              <DesktopCard key={m.year} milestone={m} index={idx} planet={PLANET_IMAGES[idx % PLANET_IMAGES.length]} />
            ))}
          </div>
        </div>

      </div>
    </section>
  );
}

/* ─── Mobile card: planet on the left line, card fills the right ─── */
function MobileCard({ milestone, index, planet }: { milestone: Milestone; index: number; planet: string }) {
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: '-60px' });

  return (
    <div className="relative">
      {/* Planet sits on the left line */}
      <div
        className="absolute -left-10 top-1/2 -translate-y-1/2 w-12 h-12 rounded-full overflow-hidden border border-border-surface z-10"
        style={{ filter: 'drop-shadow(0 0 6px rgba(200,241,53,0.35))' }}
      >
        <img
          src={planet}
          alt="planet milestone"
          className="w-full h-full object-cover"
          style={{ animation: `planet-spin ${10 + index * 2}s linear infinite` }}
        />
      </div>

      {/* Card */}
      <motion.div
        ref={ref}
        initial={{ opacity: 0, x: 20 }}
        animate={inView ? { opacity: 1, x: 0 } : {}}
        transition={{ duration: 0.5, ease, delay: index * 0.08 }}
        className="liquid-glass-card rounded-2xl p-4 sm:p-5"
      >
        <div className="flex items-center gap-2 mb-2">
          <span className="inline-flex items-center justify-center px-3 py-1 text-xs font-mono bg-accent-lime text-bg-base rounded-full flex-shrink-0">
            {milestone.year}
          </span>
          <h4 className="font-display text-text-primary text-base leading-snug">
            {milestone.title}
          </h4>
        </div>
        <p className="text-base text-text-secondary leading-relaxed">
          {milestone.description}
        </p>
      </motion.div>
    </div>
  );
}

/* ─── Desktop card: alternating left / right ─── */
function DesktopCard({ milestone, index, planet }: { milestone: Milestone; index: number; planet: string }) {
  const isLeft = index % 2 === 0;
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: '-80px' });
  const [isHovered, setIsHovered] = useState(false);

  const cardAnimate = {
    ...(inView ? { opacity: 1, y: 0 } : {}),
    ...(isHovered ? { y: -5 } : {}),
  };

  const connectorAnimate = {
    ...(isHovered ? { scale: 1.4, filter: 'drop-shadow(0 0 14px #C8F135)' } : {}),
  };

  const CardContent = () => (
    <motion.div
      ref={ref}
      initial={{ opacity: 0, y: 30 }}
      animate={cardAnimate}
      transition={{ duration: 0.6, ease }}
      className="liquid-glass-card rounded-3xl p-6 w-full max-w-[420px]"
    >
      <div className="flex items-center mb-3">
        <span className="inline-flex items-center justify-center px-3 py-1 text-sm font-mono bg-accent-lime text-bg-base rounded-full mr-2">
          {milestone.year}
        </span>
        <h4 className="font-display text-text-primary text-lg">
          {milestone.title}
        </h4>
      </div>
      <p className="text-text-secondary">{milestone.description}</p>
    </motion.div>
  );

  return (
    <div
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className="relative flex items-center w-full"
    >
      {/* Left half */}
      <div className="w-1/2 flex justify-end pr-16">
        {isLeft && <CardContent />}
      </div>

      {/* Center planet */}
      <motion.div
        animate={connectorAnimate}
        className="absolute left-1/2 -translate-x-1/2 w-16 h-16 rounded-full overflow-hidden border border-border-surface flex-shrink-0 z-10"
        style={{ filter: 'drop-shadow(0 0 8px rgba(200,241,53,0.35))' }}
      >
        <img
          src={planet}
          alt="planet milestone"
          className="w-full h-full object-cover"
          style={{ animation: `planet-spin ${10 + index * 2}s linear infinite` }}
        />
      </motion.div>

      {/* Right half */}
      <div className="w-1/2 flex justify-start pl-16">
        {!isLeft && <CardContent />}
      </div>
    </div>
  );
}

import { Github, Linkedin, Twitter } from 'lucide-react'
import { useEffect, useState } from 'react'
import { Link, useLocation } from 'react-router'

const pageLinks = [
  { label: 'Home', href: '/' },
  { label: 'About', href: '/about' },
  { label: 'Services', href: '/services' },
  { label: 'Work', href: '/work' },
  { label: 'Team', href: '/team' },
  { label: 'Blog', href: '/blog' },
  { label: 'Contact', href: '/contact' },
]

const socials = [
  { icon: Github, label: 'GitHub', href: '#' },
  { icon: Linkedin, label: 'LinkedIn', href: '#' },
  { icon: Twitter, label: 'Twitter', href: '#' },
]

export default function Footer() {
  const [aboutData, setAboutData] = useState<any>(null)
  const location = useLocation()
  const isHome = location.pathname === '/'

  useEffect(() => {
    fetch('/data/about_us.json')
      .then((res) => res.json())
      .then(setAboutData)
      .catch((err) => console.error('Failed to load about us data', err))
  }, [])

  const handleScroll = (e: React.MouseEvent<HTMLAnchorElement>, href: string) => {
    if (href.startsWith('/#') && isHome) {
      e.preventDefault()
      const id = href.replace('/#', '')
      const el = document.getElementById(id)
      if (el) el.scrollIntoView({ behavior: 'smooth' })
    }
  }

  return (
    <footer className="w-full py-12 border-t border-border-surface bg-transparent">
      <div className="max-w-[1280px] mx-auto px-6">
        <div className="flex flex-col md:flex-row items-center justify-between gap-6">
          {/* Logo */}
          <Link
            to="/"
            className="flex items-center hover:opacity-80 transition-opacity"
          >
            <img
              src="/images/company_log.png"
              alt="Universe Software"
              className="h-7 w-auto object-contain"
            />
          </Link>

          {/* Nav links */}
          <nav className="flex flex-wrap justify-center gap-6">
            {pageLinks.map((link) => (
              <Link
                key={link.label}
                to={link.href}
                onClick={(e) => handleScroll(e, link.href)}
                className="font-mono text-xs text-text-muted hover:text-text-secondary transition-colors uppercase tracking-[0.04em]"
              >
                {link.label}
              </Link>
            ))}
          </nav>

          {/* Social icons */}
          <div className="flex items-center gap-4">
            {socials.map((social) => (
              <a
                key={social.label}
                href={social.href}
                onClick={(e) => e.preventDefault()}
                className="text-text-muted hover:text-accent-lime transition-colors"
                aria-label={social.label}
              >
                <social.icon size={20} />
              </a>
            ))}
          </div>
        </div>

        {/* Bottom row */}
        <div className="text-center mt-6">
          <p className="font-mono text-[0.7rem] text-text-muted">
            &copy; {aboutData?.foundedYear || '2024'} Chakrawal Digital. Engineered in{' '}
            {aboutData?.location || 'Phnom Penh'}{' '}
            <span role="img" aria-label="Cambodia">
              🇰🇭
            </span>{' '}
            ·{' '}
            <Link to="/" className="hover:text-text-secondary transition-colors">
              Privacy Policy
            </Link>
          </p>
        </div>
      </div>
    </footer>
  )
}

